  // Животные
  topicAnimalsRu()
  {
    let tmpAr = [];
    tmpAr[0] = this.topicFishsRu();
    tmpAr[1] = this.topicBirdsRu();
    tmpAr[2] = this.topicInsectsRu();
    tmpAr[3] = this.topicMammalsRu();
    tmpAr[4] = this.topicReptilesRu();
    tmpAr[5] = this.topicAmphibiansRu();
    tmpAr[6] = this.topicInvertebratesRu();
    tmpAr[7] = this.topicDinosaursRu();

    let words = [];

    for (let i = 0; i < tmpAr.length; i++)
      for (let j = 0; j < tmpAr[i].length; j++)
        words.push(tmpAr[i][j]);

    return shuffle(words);
  }

