  // Растения
  topicPlantsRu()
  {
    let tmpAr = [];
    tmpAr[0] = this.topicTreesRu();
    tmpAr[1] = this.topicFlowersRu();
    tmpAr[2] = this.topicMushroomsRu();
    tmpAr[3] = this.topicBerriesRu();
    tmpAr[4] = this.topicUtanonRu();
    tmpAr[5] = this.topicBungaRu();

    let words = [];

    for (let i = 0; i < tmpAr.length; i++)
      for (let j = 0; j < tmpAr[i].length; j++)
        words.push(tmpAr[i][j]);

    return shuffle(words);
  }

